data.content:
**MSTest does not have `Assert.IsGreaterThan` or `Assert.IsInRange`.** Those don't exist. Here's what you actually have for numeric comparisons:

| Need | MSTest Assertion |
|---|---|
| Exact double match (with tolerance) | `Assert.AreEqual(expected, actual, delta)` |
| Arbitrary comparison | `Assert.IsTrue(value > threshold)` — but gives **poor failure messages** |
| Exception expected | `Assert.ThrowsException<T>(action)` |

For boundary tests, `Assert.AreEqual` with a delta is your primary tool. Use `Assert.IsTrue` for inequalities, but add a message parameter so failures are diagnosable:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_Partial_ReturnsExpected()
    {
        Assert.AreEqual(75.0, _calc.CalculatePercentage(3, 4), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.999, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_ResultInRange()
    {
        double result = _calc.NormalizeScore(30, 50);
        Assert.AreEqual(60.0, result, 0.001);
        // No IsInRange—use IsTrue with a message for inequalities:
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        Assert.AreEqual(100.0, _calc.NormalizeScore(120, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 50));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(10, 0));
    }
}
```

**Key takeaways:**
- **`Assert.AreEqual(expected, actual, delta)`** — the `delta` overload is essential for `double` comparisons to handle floating-point imprecision.
- **`Assert.IsTrue(condition, message)`** — always pass the `message` string; without it, a failure just says "Assert.IsTrue failed" with no context.
- **`[DataTestMethod]` + `[DataRow]`** — ideal for testing grade boundaries exhaustively without duplicate test methods.
